import React from 'react';
import { useConversation } from './hooks/useConversation';
import InputArea from './components/InputArea';

function App() {
  const { messages, isTyping, currentStep, handleUserAnswer } = useConversation();
  const latestBotMessage = messages.filter(m => m.sender === 'bot').slice(-1)[0]?.text;

  return (
    <div className="container">
      {/* 1. Header Area */}
      <div style={{ position: 'fixed', top: '40px', width: '100%', textAlign: 'center', color: '#ccc', fontSize: '12px', letterSpacing: '2px' }}>
        NIMHANS CLINICAL PROTOCOL
      </div>

      {/* 2. Main Question */}
      <main style={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
        {isTyping ? (
          <div style={{ fontSize: '18px', color: '#aaa' }}>Processing...</div>
        ) : (
          <h1>{latestBotMessage}</h1>
        )}

        <InputArea 
          currentStep={currentStep} 
          onSendMessage={handleUserAnswer} 
          isTyping={isTyping} 
        />
      </main>

      {/* 3. Bottom Progress */}
      <div style={{ position: 'fixed', bottom: '0', left: '0', height: '4px', background: '#10b981', transition: 'width 1s', width: `${(messages.filter(m => m.sender === 'bot').length / 5) * 100}%` }} />
    </div>
  );
}

export default App;
